class RealisticSlippage(SlippageModel):
    def process_order(self, data, order):
        # Use previous bar's close price, not current bar's open
        price = data.history(order.sid, 'close', 2, '1d')[0]
        return (price, order.amount)

def initialize_start(context):
    context.sym = symbol('AAPL')
    context.set_slippage(RealisticSlippage())
    schedule_function(
        func=rebal,
        date_rule=date_rules.every_day(), 
        time_rule=time_rules.market_open(),
    )

def rebal(context, data):
    target = context.wgts[context.i]
    order(context.sym, target, style=MarketOrder())
    context.i += 1
